VALUES
  ('generalpolice-8b7f1efc-moex-00222', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'essay', '警察甲與乙執行毒品查緝勤務時，查詢人民丙所駕駛之車主資料發現丙
有毒品案件前科，故攔停丙查證身分，要求丙將口袋內物品取出檢查。
丙於提出身分證件與口袋內容物後，主張其非車主，並當場請求警察甲與
乙開立並交付警察行使職權之民眾異議紀錄表，遭警察甲與乙拒絕不提
供。請問：丙得否以及以何種行政訴訟類型請求提供異議紀錄表？（25分）
參考法條：
警察職權行使法第29條第1項與第2項規定
義務人或利害關係人對警察依本法行使職權之方法、應遵守之程序或其他侵害利
益之情事，得於警察行使職權時，當場陳述理由，表示異議。
前項異議，警察認為有理由者，應立即停止或更正執行行為；認為無理由者，得繼
續執行，經義務人或利害關係人請求時，應將異議之理由製作紀錄交付之。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "e0a865ce9ca1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00223', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'essay', '丙為丁地方檢察署所屬實任檢察官，其民國 111 年年終職務評定案，經
丁地方檢察署 111 年第 1次檢察官職務評定審議會（下稱職評會）審議，
考量直屬主管與主管首長之考評紀錄以及其差假與處分紀錄後，評定結
果為「未達良好」。丙不服，經提起復審程序後仍不服，遂提起行政訴訟，
主張評定程序違法，該程序應適用行政程序法，給予陳述意見之機會，
且評定結果應敘明理由。請問：此項主張有無理由？（25分）
參考法條：
檢察官職務評定辦法
第3條第1項規定：「職務評定種類如下：一、年終評定：指對同一評定年度任職
滿一年者，評定其當年1至12月任職期間之表現……」
第9條第1項及第2項第1款規定：「各級檢察署及其檢察分署應設檢察官職務評
定審議會……」、「檢察官職務評定審議會職掌如下：一、初評檢察官職務評定事
項。」
第 10 條第 2 項規定：「職務評定審議會初評議案有疑義時，得調閱有關資料，必
要時並得通知受評人、有關人員或其主管到會備詢，詢畢退席。」', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "e0a865ce9ca1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00224', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '關於行政法之法源，下列敘述何者正確？', '["最高行政法院大法庭之裁定，對提案庭提交之事件有拘束力", "最高行政法院庭長法官聯席會議之決議，於大法庭制度實施後，即停止適用", "最高行政法院經大法庭徵詢程序統一之法律見解，依法有通案拘束下級法院之效力", "最高行政法院選編之判例，有裁判全文可查考者，其法律見解有通案拘束下級法院之效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "e0a865ce9ca1", "answer_pdf_sha1": "4d7aa157a30b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00225', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '依據司法院關於層級化法律保留原則相關解釋之意旨，下列敘述何者正確？', '["行政機關強制將感染流行性疾病之確診者隔離於特定處所一定期間，得以法律或法律授權之法 規作為依據", "行政機關於流行性疾病傳播期間禁止公務員出國旅行，僅得依法律規定，不得以法律授權之法 規作為依據", "行政機關公布違反居家隔離要求而有可能感染流行性疾病人民之姓名，得以法律或法律授權之 法規作為依據", "行政機關對因可能感染流行性疾病而居家隔離之人民提供餐點及服務，僅得依據法律，不得以 法規命令定之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "e0a865ce9ca1", "answer_pdf_sha1": "4d7aa157a30b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00226', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '依司法院解釋意旨，對人民違反行政法上義務之行為處以罰鍰，涉及對人民財產權之限制，下列 敘述何者錯誤？', '["罰鍰是立法者針對應予非難之違反行政法上義務行為給予之處罰", "立法者預留視違規情節輕重而予處罰之範圍，係屬立法形成自由", "立法者所設定之裁量範圍均應儘量放寬予行政機關決定，以避免造成個案處罰顯然過苛而有情 輕法重之情形", "處罰應視違規情節之輕重程度而為裁量，俾符合憲法責罰相當原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "e0a865ce9ca1", "answer_pdf_sha1": "4d7aa157a30b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00227', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '依現行法規定，下列何者非屬公法人？', '["國家運動訓練中心", "南投市", "高雄市那瑪夏區", "臺北翡翠水庫管理局"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "e0a865ce9ca1", "answer_pdf_sha1": "4d7aa157a30b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00228', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '法令規定直轄市人口低於200萬人者，其處、局、委員會之總數不得超過29個；高於200萬人 者，總數則不得超過32個，此與下列何種地方自治團體之權限相關？', '["地方立法自主權", "地方財政自主權", "地方組織自主權", "地方空間設置自主權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "e0a865ce9ca1", "answer_pdf_sha1": "4d7aa157a30b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00229', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '同一醫療器材申請事件，衛生福利部食品藥物管理署及經濟部產業發展署均有管轄權時，下列敘 述何者錯誤？', '["由受理在先之機關管轄", "由衛生福利部及經濟部協議決定管轄", "由衛生福利部食品藥物管理署及經濟部產業發展署協議決定管轄", "由行政院指定管轄"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "e0a865ce9ca1", "answer_pdf_sha1": "4d7aa157a30b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00230', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '關於公務員停職之規定，下列敘述何者正確？', '["主管機關對於所屬公務員依規定送請監察院彈劾，認為有免除職務等情節重大之虞者，得依職 權先行停職", "公務員停職後復職者，服務機關毋庸補給其停職期間之本俸（年功俸）或相當之給與", "公務員停職期間，亦同時喪失公務人員身分", "停職期間為6個月以上，3年以下"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "e0a865ce9ca1", "answer_pdf_sha1": "4d7aa157a30b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00231', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '依公務員服務法之規定，下列何者構成公務員違反不得兼任他項公職或業務之義務？', '["勞動部專員業餘時間無償兼任社區大學志工講師，雖未妨礙本職工作，仍報服務機關備查", "臺灣士林地方檢察署檢察官於業餘時間撰寫法庭小說並委由商業出版社出版販售，獲取相當 報酬", "擁有導遊執照之臺中市和平區公所科員，在公餘時間偶爾接受旅行社委託，以按件計酬方式擔 任原住民文化導遊，賺取薄利", "衛生所醫師依法令兼任私立醫療院所之定期駐院醫師，並就兼任部分獲有薪資"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "e0a865ce9ca1", "answer_pdf_sha1": "4d7aa157a30b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL)
